const FIXED_TITLE_NOW_MS = Number.parseInt("test", 36);

const PRE_DESCENT_KEYS = [
  "ArrowRight",
  "ArrowRight",
  "ArrowRight",
  "ArrowRight",
  "ArrowRight",
  "ArrowRight",
  "n",
  "ArrowRight",
  "ArrowRight",
  "ArrowRight",
