] as const;

const POST_PICKUP_KEYS = [
  "b",
  "ArrowDown",
  "ArrowDown",
  "ArrowDown",
  "b",
  "b",
] as const;

test("plays one deterministic mocked-director happy path", async ({ page }) => {
  await page.addInitScript((nowMs) => {
    Date.now = () => nowMs;
  }, FIXED_TITLE_NOW_MS);

  const state = page.getByTestId("game-state");

  await page.goto("/");
  await expect(state).toHaveAttribute("data-screen", "title");
  await expect(page.getByTestId("title-screen")).toBeVisible();
  await expect(page.getByTestId("title-seed")).toContainText("lantern-test");

  await page.getByTestId("new-run-button").click();
  await expect(state).toHaveAttribute("data-screen", "playing");
  await expect(state).toHaveAttribute("data-depth", "1");
  await expect(state).toHaveAttribute("data-turn", "0");
  await expect(page.getByTestId("game-grid")).toBeVisible();
  await expect(page.getByTestId("hud")).toBeVisible();
  await expect(page.getByTestId("message-log")).toBeVisible();

  let expectedTurn = 0;
  for (const key of PRE_DESCENT_KEYS) {
    expectedTurn += 1;
    await pressActionKey(page, expectedTurn, key);
  }

  expectedTurn += 1;
  await pressActionKey(page, expectedTurn, "g");

  await page.keyboard.press("i");
  await expect(state).toHaveAttribute("data-panel-mode", "inventory");
  await expect(page.getByTestId("inventory-panel")).toBeVisible();
  await page.keyboard.press("i");
  await expect(state).toHaveAttribute("data-panel-mode", "inspect");

  for (const key of POST_PICKUP_KEYS) {
    expectedTurn += 1;
    await pressActionKey(page, expectedTurn, key);
  }

  await expect(state).toHaveAttribute("data-turn", "19");
  await page.keyboard.press(">");
  const transition = page.getByTestId("transition-overlay");
  await expect(transition).toHaveAttribute("data-transition-phase", "descending");
  await expect(transition).toHaveAttribute("data-skip-enabled", "true");
  await page.keyboard.press("Space");

  await expect(state).toHaveAttribute("data-depth", "2");
  await expect(state).toHaveAttribute("data-turn", "20");
  await expect(state).toHaveAttribute("data-input-locked", "false");
  await expect(page.getByTestId("game-grid")).toBeVisible();
  await expect(page.getByTestId("hud")).toBeVisible();
  await expect(page.getByTestId("message-log")).toBeVisible();

  await page.keyboard.press("q");
  await expect(state).toHaveAttribute("data-panel-mode", "quest");
  await expect(page.getByTestId("quest-panel")).toBeVisible();
  await page.keyboard.press("Escape");
  await expect(state).toHaveAttribute("data-panel-mode", "inspect");

  await page.keyboard.press("Tab");
  await expect(state).toHaveAttribute("data-diary-open", "true");
  await expect(page.getByTestId("diary-layer")).toBeVisible();
  await expect(page.getByTestId("dungeon-diary")).toHaveAttribute(
    "data-diary-mode",
    "partial",
  );
  await page.keyboard.press("Tab");
  await expect(state).toHaveAttribute("data-diary-open", "false");
  await expect(page.getByTestId("diary-layer")).toBeHidden();

  await page.keyboard.press("Escape");
  await expect(page.locator('[data-confirm-prompt="true"]')).toContainText(
    "Abandon the run? y/n",
  );
  await expect(state).toHaveAttribute("data-screen", "playing");
  await page.keyboard.press("y");
  await expect(state).toHaveAttribute("data-screen", "summary");
  await expect(state).toHaveAttribute("data-terminal-status", "ABORTED");
  await expect(page.getByTestId("summary-screen")).toBeVisible();
  await expect(page.getByTestId("dungeon-diary")).toHaveAttribute(
    "data-diary-mode",
    "final",
  );

  await page.getByTestId("run-index-button").click();
  await expect(state).toHaveAttribute("data-screen", "run-index");
  await expect(page.getByTestId("run-index")).toBeVisible();
  await expect(page.getByTestId("run-index-entry")).toHaveCount(1);
  await expect(page.getByTestId("run-index-entry").first()).toHaveAttribute(
    "data-outcome",
    "abort",
  );
});

const pressActionKey = async (
  page: Page,
  expectedTurn: number,
  key: string,
): Promise<void> => {
  const state = page.getByTestId("game-state");

  await expect(state).toHaveAttribute("data-input-locked", "false");
  await page.keyboard.press(key);
  await expect(state).toHaveAttribute("data-turn", String(expectedTurn));
  await expect(state).toHaveAttribute("data-input-locked", "false");
};

import type {
  InspectCard,
  InventoryActionView,
  InventoryEntry,
  InventoryView,
} from "../model";

type InventoryPanelProps = {
  readonly view: InventoryView;
  readonly selectedEntry: InventoryEntry | null;
  readonly selectedEntryIndex: number;
  readonly selectedActionIndex: number;
  readonly actions: readonly InventoryActionView[];
  readonly card: InspectCard | null;
  readonly throwPrompt: boolean;
  readonly onSelectEntry: (index: number) => void;
  readonly onSelectAction: (index: number) => void;
  readonly onRunAction: (index: number) => void;
};

export function InventoryPanel({
  view,
  selectedEntry,
  selectedEntryIndex,
  selectedActionIndex,
  actions,
  card,
  throwPrompt,
  onSelectEntry,
  onSelectAction,
  onRunAction,
}: InventoryPanelProps) {
  const allEntries = [...view.slots, ...view.equipment];

  return (
    <div
      className="grid h-full min-h-0 grid-rows-[auto_minmax(0,1fr)_auto] gap-3 p-3 text-left"
      data-testid="inventory-panel"
    >
      <div>
        <h2 className="text-sm font-semibold normal-case tracking-normal text-gg-text">
          Inventory
        </h2>
        <p className="text-xs normal-case tracking-normal text-gg-muted">
          {filledSlots(view.slots)}/16 slots
        </p>
      </div>

      <div className="grid min-h-0 grid-cols-[minmax(0,1fr)_minmax(8rem,0.8fr)] gap-3">
        <div className="min-h-0 overflow-auto">
          <div className="grid grid-cols-4 gap-1" aria-label="Inventory slots">
            {view.slots.map((entry) => {
              const index = allEntries.findIndex((candidate) => candidate.id === entry.id);
              return (
                <button
                  className={slotClass(index === selectedEntryIndex, entry.empty)}
                  data-inventory-slot={entry.index}
                  key={entry.id}
                  type="button"
                  onClick={() => onSelectEntry(index)}
                >
                  <span className="text-[0.62rem] text-gg-muted">
                    {entry.index + 1}
                  </span>
                  <span className="truncate">{entry.label}</span>
                </button>
              );
            })}
          </div>

          <div className="mt-3 space-y-1" aria-label="Equipment slots">
            {view.equipment.map((entry) => {
              const index = allEntries.findIndex((candidate) => candidate.id === entry.id);
              return (
                <button
                  className={equipmentClass(index === selectedEntryIndex)}
                  data-equipment-slot={entry.id}
                  key={entry.id}
                  type="button"
                  onClick={() => onSelectEntry(index)}
                >
                  {entry.label}
                </button>
              );
            })}
          </div>
        </div>

        <SelectionCard card={card} selectedEntry={selectedEntry} />
      </div>

      <div className="border-t border-gg-border pt-2">
        {throwPrompt ? (
          <div
            className="rounded border border-amber-300/35 bg-amber-300/10 px-2 py-1 text-xs font-semibold normal-case tracking-normal text-amber-100"
            data-throw-direction-prompt="true"
          >
            Throw direction
          </div>
        ) : null}
        <div className="mt-2 flex flex-wrap gap-1" aria-label="Inventory actions">
          {actions.length === 0 ? (
            <span className="text-xs normal-case tracking-normal text-gg-muted">
              No actions.
            </span>
          ) : (
            actions.map((action, index) => (
              <button
                className={actionClass(
                  index === selectedActionIndex,
                  action.enabled,
                )}
                data-action-id={action.id}
                data-disabled-reason={action.reason ?? ""}
                disabled={!action.enabled}
                key={action.id}
                type="button"
                title={action.reason ?? action.label}
                onClick={() => {
                  onSelectAction(index);
                  onRunAction(index);
                }}
              >
                {index + 1}. {action.label}
                {action.enabled ? null : (
                  <span className="ml-1 text-amber-200">({action.reason})</span>
                )}
              </button>
            ))
          )}
        </div>
      </div>
    </div>
  );
}

function SelectionCard({
  card,
  selectedEntry,
}: {
  readonly card: InspectCard | null;
  readonly selectedEntry: InventoryEntry | null;
}) {
  if (card === null || selectedEntry?.stack === null) {
    return (
      <div className="rounded border border-gg-border p-2 text-xs normal-case tracking-normal text-gg-muted">
        Empty slot
      </div>
    );
  }

  return (
    <div className="min-h-0 overflow-auto rounded border border-gg-border p-2 text-xs normal-case tracking-normal">
      <div className="mb-2 flex items-center gap-2">
        <span
          className="grid h-7 w-7 place-items-center rounded bg-black/25 text-base font-bold text-gg-text"
          aria-hidden="true"
        >
          {card.glyph}
        </span>
        <div className="min-w-0">
          <h3 className="truncate font-semibold text-gg-text">{card.title}</h3>
          <p className="truncate text-gg-muted">{card.descriptor}</p>
        </div>
      </div>
      <dl className="grid grid-cols-[4.5rem_minmax(0,1fr)] gap-x-2 gap-y-1">
        {card.lines.map((line) => (
          <FragmentDetail key={`${line.label}:${line.value}`} {...line} />
        ))}
      </dl>
      {card.unknown.map((line) => (
        <p className="mt-1 font-semibold text-amber-200" key={line}>
          {line}
        </p>
      ))}
    </div>
  );
}

function FragmentDetail({
  label,
  value,
}: {
  readonly label: string;
  readonly value: string;
}) {
  return (
    <>
      <dt className="text-gg-muted">{label}</dt>
      <dd className="truncate text-gg-text">{value}</dd>
    </>
  );
}

const filledSlots = (slots: readonly InventoryEntry[]): number =>
  slots.filter((slot) => !slot.empty).length;

const slotClass = (selected: boolean, empty: boolean): string =>
  [
    "grid h-14 min-w-0 grid-rows-[auto_minmax(0,1fr)] rounded border px-1.5 py-1 text-left text-[0.68rem] normal-case tracking-normal",
    selected ? "border-gg-accent bg-gg-accent/15 text-gg-text" : "border-gg-border bg-black/15 text-gg-text",
    empty ? "text-gg-muted" : "",
  ]
    .filter(Boolean)
    .join(" ");

const equipmentClass = (selected: boolean): string =>
  [
    "block w-full truncate rounded border px-2 py-1 text-left text-xs normal-case tracking-normal",
    selected ? "border-gg-accent bg-gg-accent/15 text-gg-text" : "border-gg-border bg-black/15 text-gg-text",
  ].join(" ");

const actionClass = (selected: boolean, enabled: boolean): string =>
  [
    "rounded border px-2 py-1 text-xs font-semibold normal-case tracking-normal",
    selected ? "border-gg-accent bg-gg-accent/15" : "border-gg-border bg-black/15",
    enabled ? "text-gg-text" : "cursor-not-allowed text-gg-muted",
  ].join(" ");

function chebyshev(
  left: { readonly x: number; readonly y: number },
  right: { readonly x: number; readonly y: number },
): number {
  return Math.max(Math.abs(left.x - right.x), Math.abs(left.y - right.y));
}

async function progressSignature(
  page: Page,
  shell: ShellSnapshot,
): Promise<string> {
  const player = await readPlayerPosition(page);
  return JSON.stringify({
    depth: shell.depth,
    turn: shell.turn,
    panel: shell.panelMode,
    player,
  });
}

class BotFailure extends Error {
  constructor(
    message: string,
    readonly diagnosis: BotDiagnosis,
  ) {
    super(message);
    this.name = "BotFailure";
  }
}

export function seedToTitleNowMs(seed: string): number {
  if (seed.startsWith("lantern-")) {
    const suffix = seed.slice("lantern-".length);
    const parsed = Number.parseInt(suffix, 36);
    if (Number.isFinite(parsed)) {
      return parsed;
    }
  }

  return Number.parseInt("test", 36);
}

export function resolveCampaignSeed(): string {
  const fromEnv = process.env.SEED?.trim();
  if (fromEnv !== undefined && fromEnv.length > 0) {
    return fromEnv;
  }

  return "lantern-test";
}

