const waitForPromiseSync = <T>(
  promise: Promise<T>,
  timeoutMs: number,
  clock: PrefetchClock,
): T | null => {
  if (timeoutMs <= 0) {
    return null;
  }

  const { port1, port2 } = new MessageChannel();
  let settled = false;
  let value: T | null = null;

  void promise.then(
    (resolved) => {
      value = resolved;
      settled = true;
      port1.postMessage("done");
    },
    () => {
      settled = true;
      port1.postMessage("done");
    },
  );

  const deadline = clock() + timeoutMs;
  while (!settled && clock() < deadline) {
    const remaining = deadline - clock();
    if (remaining <= 0) {
      break;
    }

    waitOnPort(port2, Math.min(SYNC_WAIT_SLICE_MS, remaining));
  }

  return settled ? value : null;
};

const withoutPlacementHint = <
  T extends { readonly placementHint: FloorManifest["roster"][number]["placementHint"] },
>(
  entry: T,
): Omit<T, "placementHint"> => {
  const copy = { ...entry } as {
    placementHint?: FloorManifest["roster"][number]["placementHint"];
  } & Record<string, unknown>;
  delete copy.placementHint;
  return copy as Omit<T, "placementHint">;
};

const manifestRosterToDefinitions = (
  roster: readonly ManifestRosterEntry[],
): readonly EnemyDefinition[] => roster.map(withoutPlacementHint);

const manifestItemsToDefinitions = (
  items: readonly ManifestItemEntry[],
): readonly ItemDefinition[] => items.map(withoutPlacementHint);

const manifestTrapsToDefinitions = (
  traps: readonly ManifestTrapEntry[],
): readonly TrapDefinition[] => traps.map(withoutPlacementHint);

const manifestNpcsToDefinitions = (
  npcs: readonly ManifestNpcEntry[],
): readonly NpcDefinition[] => npcs.map(withoutPlacementHint);

const materializedToFloorContent = (
  floor: MaterializedFloor,
  seed: string,
): FloorContent => {
  const manifest = floor.manifest;

  return {
    params: {
      ...manifest.params,
      seed,
    },
    roster: floor.runtime.roster.length > 0
      ? floor.runtime.roster
      : manifestRosterToDefinitions(manifest.roster),
    items: manifestItemsToDefinitions(manifest.items),
    traps: manifestTrapsToDefinitions(manifest.traps),
    npcs: manifestNpcsToDefinitions(manifest.npcs),
    ...(manifest.quest === null ? {} : { quest: manifest.quest }),
  };
};

const generatedResultToFloorContent = (
  floor: MaterializedFloor | FloorContent,
  seed: string,
): FloorContent =>
  "manifest" in floor ? materializedToFloorContent(floor, seed) : floor;

export const createPrefetchController = (
  options: PrefetchControllerOptions,
): PrefetchController => {
  const gameConfig = options.gameConfig ?? config;
  const gameBounds = options.gameBounds ?? bounds;
  const stairsCapMs = options.prefetch?.stairsCapMs ?? DEFAULT_STAIRS_CAP_MS;
  const clock = options.clock ?? createPrefetchCounterClock();
  const fallbackProvider =
    options.fallbackProvider ?? createFallbackFloorContentProvider();

  let cancelled = false;
  let readySlot: ReadySlot | null = null;
  let inFlightSlot: InFlightSlot | null = null;
  let lastStatus: PrefetchStatus = { status: "idle" };
  const discards: DiscardedPrefetch[] = [];
  const servedSources = new Map<number, ServedFloorSource>();
  let currentFloorDepth = 0;

  const setStatus = (status: PrefetchStatus): void => {
    lastStatus = status;
  };

  const buildPrompt = (depth: number, trace: ParsedTrace): string => {
    const band = depthBandForDepth(depth, gameConfig);
    const traceFacts = summarizeTrace(trace, { band });

    return assemblePrompt({
      band,
      depth,
      config: gameConfig,
      bounds: gameBounds,
      traceFacts,
      runContext: {
        seed: options.seed,
        runId: options.runId,
      },
    });
  };

  const buildGenerateContext = (
    depth: number,
    prompt: string,
    signal: AbortSignal,
  ): GenerateFloorContext => ({
    prompt,
    provider: options.provider,
    runId: options.runId,
    depth,
    seed: options.seed,
    modelId: options.modelId,
    ...(options.now === undefined ? {} : { now: options.now }),
    ...(options.repairCap === undefined ? {} : { repairCap: options.repairCap }),
    ...(options.gate2 === undefined ? {} : { gate2: options.gate2 }),
    fallbackProvider,
    ...(options.artifacts === undefined ? {} : { artifacts: options.artifacts }),
    providerOptions: {
      timeoutMs: options.providerGenerationTimeoutMs
        ?? gameConfig.director.manifestTimeoutMs,
      ...(signal.aborted ? { timeoutMs: 1 } : {}),
    },
  });

  const recordDiscard = (depth: number, reason: string): void => {
    if (readySlot?.depth === depth) {
      readySlot = null;
    }

    discards.push({
      depth,
      reason,
      atMs: clock(),
    });
    setStatus({ status: "discarded", depth, reason });
  };

  const completeGeneration = (
    depth: number,
    content: FloorContent,
    source: ServedFloorSource,
  ): void => {
    if (cancelled) {
      recordDiscard(depth, "cancelled");
      return;
    }

    const priorSource = servedSources.get(depth);
    if (priorSource === "fallback" && currentFloorDepth >= depth) {
      recordDiscard(depth, "fallback_already_served");
      return;
    }

    if (readySlot !== null && readySlot.depth !== depth) {
      recordDiscard(readySlot.depth, "superseded_by_new_prefetch");
    }

    readySlot = { depth, content, source };
    setStatus({ status: "ready", depth });
  };

  const runGeneration = async (
    depth: number,
    trace: ParsedTrace,
    abortController: AbortController,
    releaseGlobal: () => void,
    globalGate: Promise<void>,
  ): Promise<void> => {
    const prompt = buildPrompt(depth, trace);

    try {
      const result = await generateFloor(
        buildGenerateContext(depth, prompt, abortController.signal),
      );

      if (cancelled || abortController.signal.aborted) {
        recordDiscard(depth, "cancelled");
        return;
      }

      const source: ServedFloorSource =
        result.record.outcome.kind === "manifest" ? "generated" : "fallback";
      const content = generatedResultToFloorContent(result.floor, options.seed);
      completeGeneration(depth, content, source);
    } finally {
      releaseGlobal();
      if (globalGenerationInFlight === globalGate) {
        globalGenerationInFlight = null;
      }
    }
  };

  const startPrefetch = (depth: number, trace: ParsedTrace): void => {
    if (cancelled) {
      return;
    }

    if (depth < 1 || depth > gameConfig.runStructure.depthFloors) {
      return;
    }

    if (readySlot?.depth === depth) {
      return;
    }

    if (inFlightSlot?.depth === depth) {
      return;
    }

    if (inFlightSlot !== null) {
      return;
    }

    if (globalGenerationInFlight !== null) {
      return;
    }

    const abortController = new AbortController();
    const startedAtMs = clock();
    let releaseGlobal: (() => void) | undefined;
    const globalGate = new Promise<void>((resolve) => {
      releaseGlobal = resolve;
    });
    globalGenerationInFlight = globalGate;

    const promise = runGeneration(
      depth,

      depth,
      trace,
      abortController,
      releaseGlobal!,
      globalGate,
    ).finally(() => {
      if (inFlightSlot?.promise === promise) {
        inFlightSlot = null;
        if (readySlot === null) {
          setStatus({ status: "idle" });
        }
      }
    });

    inFlightSlot = {
      depth,
      startedAtMs,
      promise,
      abortController,
    };
    setStatus({ status: "in_flight", depth, startedAtMs });
  };

  const consumeReady = (depth: number): ReadySlot | null => {
    if (readySlot?.depth !== depth) {
      return null;
    }

    const slot = readySlot;
    readySlot = null;
    setStatus({ status: "idle" });
    return slot;
  };

  const serveFallback = (depth: number, seed: string): ServedFloor => {
    const content = fallbackProvider.getFloor(depth, seed);
    servedSources.set(depth, "fallback");

    return {
      content,
      source: "fallback",
      depth,
    };
  };

  const waitForReadySlot = async (
    depth: number,
    startedAtMs: number,
  ): Promise<ReadySlot | null> => {
    const deadline = startedAtMs + stairsCapMs;

    while (clock() < deadline) {
      const ready = consumeReady(depth);
      if (ready !== null) {
        return ready;
      }

      if (inFlightSlot?.depth !== depth) {
        return null;
      }

      await new Promise<void>((resolve) => {
        setTimeout(resolve, SYNC_WAIT_SLICE_MS);
      });
    }

    return consumeReady(depth);
  };

  const servedFromReady = (ready: ReadySlot, seed: string): ServedFloor => {
    servedSources.set(ready.depth, ready.source);

    return {
      content: {
        ...ready.content,
        params: {
          ...ready.content.params,
          seed,
        },
      },
      source: ready.source,
      depth: ready.depth,
    };
  };

  const resolveFloor = async (
    depth: number,
    seed: string,
  ): Promise<ServedFloor> => {
    const ready = consumeReady(depth);
    if (ready !== null) {
      return servedFromReady(ready, seed);
    }

    if (inFlightSlot?.depth === depth) {
      const waited = await waitForReadySlot(depth, inFlightSlot.startedAtMs);
      if (waited !== null) {
        return servedFromReady(waited, seed);
      }

      return serveFallback(depth, seed);
    }

    startPrefetch(depth, emptyTrace(options.runId, options.seed));
    return serveFallback(depth, seed);
  };

  const onFloorEnter = (depth: number, trace: ParsedTrace): void => {
    currentFloorDepth = depth;
    startPrefetch(depth + 1, trace);
  };

  const getFloor = (depth: number, seed: string): FloorContent => {
    const ready = consumeReady(depth);
    if (ready !== null) {
      servedSources.set(depth, ready.source);
      startPrefetch(depth + 1, emptyTrace(options.runId, options.seed));
      return {
        ...ready.content,
        params: {
          ...ready.content.params,
          seed,
        },
      };
    }

    if (inFlightSlot?.depth === depth) {
      const remainingMs = Math.max(
        0,
        stairsCapMs - (clock() - inFlightSlot.startedAtMs),
      );
      const resolved = waitForPromiseSync(
        inFlightSlot.promise.then(() => consumeReady(depth)),
        remainingMs,
        clock,
      );

      if (resolved !== null) {
        servedSources.set(depth, resolved.source);
        startPrefetch(depth + 1, emptyTrace(options.runId, options.seed));
        return {
          ...resolved.content,
          params: {
            ...resolved.content.params,
            seed,
          },
        };
      }

      const served = serveFallback(depth, seed);
      return served.content;
    }

    startPrefetch(depth, emptyTrace(options.runId, options.seed));
    return serveFallback(depth, seed).content;
  };

  const pollStatus = (): PrefetchStatus => {
    if (cancelled) {
      return { status: "idle" };
    }

    if (readySlot !== null) {
      return { status: "ready", depth: readySlot.depth };
    }

    if (inFlightSlot !== null) {
      return {
        status: "in_flight",
        depth: inFlightSlot.depth,
        startedAtMs: inFlightSlot.startedAtMs,
      };
    }

    return lastStatus.status === "discarded"
      ? lastStatus
      : { status: "idle" };
  };

  const cancel = (): void => {
    cancelled = true;
    inFlightSlot?.abortController.abort();
    inFlightSlot = null;
    readySlot = null;
    setStatus({ status: "idle" });
  };

  return {
    onFloorEnter,
    getFloor,
    resolveFloor,
    pollStatus,
    cancel,
    getDiscards: () => discards,
  };
};

export class DirectorFloorProvider implements FloorContentProvider {
  private readonly controller: PrefetchController;

  constructor(controller: PrefetchController) {
    this.controller = controller;
  }

  getFloor(depth: number, seed: string): FloorContent {
    return this.controller.getFloor(depth, seed);
  }
}

export const createDirectorFloorProvider = (
  options: PrefetchControllerOptions,
): DirectorFloorProvider =>
  new DirectorFloorProvider(createPrefetchController(options));

export const resetGlobalGenerationSemaphoreForTests = (): void => {
  globalGenerationInFlight = null;
};

const emptyTrace = (runId: string, seed: string): ParsedTrace => ({
  header: {
    recordType: "header",
    protocolVersion: "1.2.0",
    engineVersion: "0.0.0",
    modelId: "prefetch",
    contentRef: { providerId: "prefetch", packVersion: "0.0.0" },
    seed,
    createdAt: "2026-06-12T00:00:00.000Z",
    runId,
  },
  turns: [],
});

  const quest =
    record.quest === undefined
      ? undefined
      : QuestDefinitionSchema.safeParse(record.quest);
  if (quest !== undefined && !quest.success) {
    return malformed(depth, `quest is malformed: ${quest.error.message}`);
  }

  return {
    ok: true,
    content: {
      params: params.value,
      roster: roster.data,
      items: items.data,
      traps: traps.data,
      npcs: npcs.data,
      ...(quest?.success ? { quest: quest.data } : {})
    }
  };
};

const parseRunFloorParams = (
  value: unknown,
  depth: number,
  gameConfig: GameConfig
):
  | { readonly ok: true; readonly value: RunFloorParams }
  | { readonly ok: false; readonly message: string } => {
  const record = asRecord(value);
  if (record === null) {
    return { ok: false, message: "params must be an object" };
  }

  const bandOrSize = parseBandOrSize(record.bandOrSize);
  if (bandOrSize === null) {
    return { ok: false, message: "params.bandOrSize is malformed" };
  }

  const roomCountRange = parseRoomCountRange(record.roomCountRange);
  if (roomCountRange === null) {
    return { ok: false, message: "params.roomCountRange is malformed" };
  }

  if (!isLayoutFlavor(record.flavor)) {
    return { ok: false, message: "params.flavor is malformed" };
  }

  if (typeof record.seed !== "string" || record.seed.length === 0) {
    return { ok: false, message: "params.seed must be a non-empty string" };
  }

  const hoard =
    record.hoard === undefined ? undefined : parseHoardParams(record.hoard);
  if (hoard === null) {
    return { ok: false, message: "params.hoard is malformed" };
  }

  const finalDepth = gameConfig.runStructure.depthFloors;
  if (depth === finalDepth && hoard === undefined) {
    return {
      ok: false,
      message: "final floor params must include params.hoard"
    };
  }

  if (depth !== finalDepth && hoard !== undefined) {
    return {
      ok: false,
      message: "params.hoard is only valid on the final floor"
    };
  }

  return {
    ok: true,
    value: {
      bandOrSize,
      roomCountRange,
      flavor: record.flavor,
      seed: record.seed,
      ...(hoard === undefined ? {} : { hoard })
    }
  };
};

const parseBandOrSize = (value: unknown): FloorParams["bandOrSize"] | null => {
  if (value === "shallows" || value === "middle" || value === "lowest") {
    return value;
  }

  const record = asRecord(value);
  if (
    record !== null &&
    isPositiveSafeInteger(record.width) &&
    isPositiveSafeInteger(record.height)
  ) {
    return {
      width: record.width,
      height: record.height
    };
  }

import { idx, type Tile } from "../map/index.js";
import type {
  EntityId,
  EntityInstance,
  GameState,
  Position,
} from "../state/index.js";
import {
  defaultVisibleFog,
  fogFromState,
  floorKnowledge,
  gridFromState,
  isTrapRevealed,
} from "./floor-runtime.js";
import {
  enemyGlyph,
  GLYPH_NPC,
  GLYPH_PLAYER,
  GLYPH_TRAP,
  itemGlyph,
  rememberedTerrainGlyph,
  terrainGlyph,
} from "./glyphs.js";

export const renderHudLine = (state: GameState): string => {
  const statuses = state.player.statuses
    .map((application) => application.status)
    .join(",");
  const statusSuffix = statuses.length > 0 ? ` ${statuses}` : "";

  return [
    `d${state.run.depth}`,
    `t${state.run.turn}`,
    `HP ${state.player.hp.current}/${state.player.hp.max}`,
    `full ${state.player.fullness.current}/${state.player.fullness.max}`,
    `L${state.player.level}`,
    `xp ${state.player.xp}${statusSuffix}`,
  ].join(" ");
};

export const render = (state: GameState): string => {
  const grid = gridFromState(state);

  if (grid === null) {
    return renderHudLine(state);
  }

  const fog = fogFromState(state, grid) ?? defaultVisibleFog(grid);
  const knowledge = floorKnowledge(state);
  const mapRevealed = knowledge.mapRevealed === true;
  const lines: string[] = [];

  for (let y = 0; y < grid.height; y += 1) {
    let row = "";

    for (let x = 0; x < grid.width; x += 1) {
      const position = { x, y };
      const index = idx(grid, position);
      const memory = fog.tiles[index];

      if (memory === undefined) {
        row += " ";
        continue;
      }

      if (!mapRevealed && memory.state === "unseen") {
        row += " ";
        continue;
      }

      if (!mapRevealed && memory.state === "remembered") {
        const tile = memory.rememberedTile;

        row += tile === null ? " " : rememberedTerrainGlyph(tile);
        continue;
      }

      const tile = grid.tiles[index];

      row +=
        tile === undefined ? " " : glyphAt(state, position, tile);
    }

    lines.push(row);
  }

  lines.push(renderHudLine(state));

  return lines.join("\n");
};

const glyphAt = (state: GameState, position: Position, tile: Tile): string => {
  if (
    state.player.position.x === position.x &&
    state.player.position.y === position.y
  ) {
    return GLYPH_PLAYER;
  }

  const entities = entitiesAt(state, position);

  const enemy = entities.find((entity) => entity.kind === "enemy");

  if (enemy !== undefined) {
    return enemyGlyph(enemy.definition.glyph);
  }

  const npc = entities.find((entity) => entity.kind === "npc");

  if (npc !== undefined) {
    return GLYPH_NPC;
  }

  const item = entities.find((entity) => entity.kind === "item");

  if (item !== undefined) {
    return itemGlyph(item.definition, item.identified);
  }

  const trap = entities.find((entity) => entity.kind === "trap");

  if (
    trap !== undefined &&
    isTrapRevealed(state, trap.id, trap.behaviorRuntime)
  ) {
    return GLYPH_TRAP;
  }

  return terrainGlyph(tile);
};

const entitiesAt = (
  state: GameState,
  position: Position,
): readonly EntityInstance[] =>
  Object.values(state.entities)
    .filter(
      (entity) =>
        entity.position.x === position.x && entity.position.y === position.y,
    )
    .sort((left, right) => compareEntityIds(left.id, right.id));

const compareEntityIds = (left: EntityId, right: EntityId): number => {
  const parsedLeft = parseEntityId(left);
  const parsedRight = parseEntityId(right);
  const kindOrder = parsedLeft.kind.localeCompare(parsedRight.kind);

  return kindOrder === 0
    ? parsedLeft.index - parsedRight.index
    : kindOrder;
};

const parseEntityId = (
  id: EntityId,
): { readonly kind: string; readonly index: number } => {
  const [kind, rawIndex] = id.split("#");

  return {
    kind: kind ?? "",
    index: Number.parseInt(rawIndex ?? "0", 10),
  };
};

const entitiesByCell = (
  state: GameState,
): ReadonlyMap<string, readonly EntityInstance[]> => {
  const grouped = new Map<string, EntityInstance[]>();
  const entities = Object.values(state.entities).sort(compareEntities);

  for (const entity of entities) {
    const key = keyForPosition(entity.position);
    const existing = grouped.get(key);

    if (existing === undefined) {
      grouped.set(key, [entity]);
    } else {
      existing.push(entity);
    }
  }

  return grouped;
};

const compareEntities = (
  left: EntityInstance,
  right: EntityInstance,
): number => {
  const kindDelta = ENTITY_KIND_ORDER[left.kind] - ENTITY_KIND_ORDER[right.kind];

  if (kindDelta !== 0) {
    return kindDelta;
  }

  return compareEntityIds(left.id, right.id);
};

const compareEntityIds = (left: EntityId, right: EntityId): number => {
  const parsedLeft = parseEntityId(left);
  const parsedRight = parseEntityId(right);
  const kindOrder = parsedLeft.kind.localeCompare(parsedRight.kind);

  return kindOrder === 0
    ? parsedLeft.index - parsedRight.index
    : kindOrder;
};

const parseEntityId = (
  id: EntityId,
): { readonly kind: string; readonly index: number } => {
  const [kind, rawIndex] = id.split("#");

  return {
    kind: kind ?? "",
    index: Number.parseInt(rawIndex ?? "0", 10),
  };
};

const fogStatesForState = (
  state: GameState,
  width: number,
  height: number,
): readonly GridFogState[] => {
  const count = width * height;

  if (count <= 0) {
    return [];
  }

  const grid = gridFromState(state);

  if (
    grid === null ||
    grid.width !== width ||
    grid.height !== height ||
    grid.tiles.length !== count
  ) {
    return Array.from({ length: count }, () => "visible");
  }

  if (floorKnowledge(state).mapRevealed === true) {
    return Array.from({ length: count }, () => "visible");
  }

  const fog = fogFromState(state, grid) ?? defaultVisibleFog(grid);

  return fog.tiles.map((tile) => {
    switch (tile.state) {
      case "visible":
      case "remembered":
      case "unseen":
        return tile.state;
      default:
        return "unseen";
    }
  });
};

const effectsSinceLastRender = (
  state: GameState,
  previousCursor?: GridRenderCursor,
): ReadonlyMap<string, CellEffects> => {
  const cursor = cursorForState(state);
  const canDiff =
    previousCursor !== undefined &&
    previousCursor.runId === cursor.runId &&
    previousCursor.floorId === cursor.floorId &&
    previousCursor.logLength <= cursor.logLength;

  if (!canDiff) {
    return new Map();
  }

  const events = (state.log as readonly RuntimeLogEvent[]).slice(
    previousCursor.logLength,
  );

  if (events.length === 0) {
    return new Map();
  }

  const positionsByActorId = actorPositions(state);
  const effectsByPosition = new Map<string, MutableCellEffects>();

  events.forEach((event, eventIndex) => {
    applyPulseEvent(event, eventIndex, positionsByActorId, effectsByPosition);
    applyMovementEvent(event, positionsByActorId, effectsByPosition);
  });

  return new Map(
    [...effectsByPosition.entries()].map(([key, effects]) => [
      key,
      {
        pulses: effects.pulses,
        hitFlash: effects.hitFlash,
        motion: effects.motion,
      },
    ]),
  );
};

const applyPulseEvent = (
  event: RuntimeLogEvent,
  eventIndex: number,
  positionsByActorId: ReadonlyMap<string, Position>,
  effectsByPosition: Map<string, MutableCellEffects>,
): void => {
  const data = asRecord(event.data);
  const eventId = `${String(event.turn ?? "t")}:${String(event.type)}:${eventIndex}`;

  switch (event.type) {
    case "attack_hit": {
      const defenderId = stringValue(data?.defenderId);
      const damage = numberValue(data?.damage);

      if (defenderId !== null && damage !== null && damage > 0) {
        addPulseForActor(
          defenderId,
          positionsByActorId,
          effectsByPosition,
          {
            id: eventId,
            kind: "damage",
            text: `-${damage}`,
          },
        );
      }
      break;
    }
    case "status_tick": {
      const entityId = stringValue(data?.entityId);
      const hpDelta = numberValue(data?.hpDelta);

      if (entityId !== null && hpDelta !== null && hpDelta !== 0) {
        addPulseForActor(
          entityId,
          positionsByActorId,
          effectsByPosition,
          pulseForDelta(eventId, hpDelta),
        );
      }
      break;
    }
    case "starvation": {
      const hpBefore = numberValue(data?.hpBefore);
      const hpAfter = numberValue(data?.hpAfter);

      if (hpBefore !== null && hpAfter !== null && hpAfter !== hpBefore) {
        addPulseForActor(
          "player",
          positionsByActorId,
          effectsByPosition,
          pulseForDelta(eventId, hpAfter - hpBefore),
        );
      }
      break;
    }
    case "level_up": {
      const hpBefore = numberValue(data?.currentHpBefore);
      const hpAfter = numberValue(data?.currentHpAfter);

      if (hpBefore !== null && hpAfter !== null && hpAfter !== hpBefore) {
        addPulseForActor(
          "player",
          positionsByActorId,
          effectsByPosition,
          pulseForDelta(eventId, hpAfter - hpBefore),
        );
      }
      break;
    }
    case "effect_executed": {
      const verb = stringValue(data?.verb);
      const targetId = stringValue(data?.targetId);
      const details = asRecord(data?.details);
      const hpBefore = numberValue(details?.hpBefore);
      const hpAfter = numberValue(details?.hpAfter);

      if (
        targetId !== null &&
        hpBefore !== null &&
        hpAfter !== null &&
        hpAfter !== hpBefore &&
        (verb === "damage" || verb === "heal")
      ) {
        addPulseForActor(
          targetId,
          positionsByActorId,
          effectsByPosition,
          pulseForDelta(eventId, hpAfter - hpBefore),
        );
      }
      break;
    }
  }
};

const applyMovementEvent = (
  event: RuntimeLogEvent,
  positionsByActorId: ReadonlyMap<string, Position>,
  effectsByPosition: Map<string, MutableCellEffects>,
): void => {
  if (event.type !== "moved" && event.type !== "enemy_moved") {
    return;
  }

  const data = asRecord(event.data);
  const actorId = stringValue(data?.actorId);
  const from = positionValue(data?.from);
  const to = positionValue(data?.to) ?? (actorId === null
    ? null
    : positionsByActorId.get(actorId) ?? null);

  if (from === null || to === null) {
    return;
  }

  const effects = mutableEffectsAt(effectsByPosition, to);
  effects.motion = {
    dx: from.x - to.x,
    dy: from.y - to.y,
  };
};

const pulseForDelta = (id: string, delta: number): GridPulse => ({
  id,
  kind: delta < 0 ? "damage" : "heal",
  text: `${delta > 0 ? "+" : ""}${delta}`,
});

const addPulseForActor = (
  actorId: string,
  positionsByActorId: ReadonlyMap<string, Position>,
  effectsByPosition: Map<string, MutableCellEffects>,
  pulse: GridPulse,
): void => {
  const position = positionsByActorId.get(actorId);

  if (position === undefined) {
    return;
  }

  const effects = mutableEffectsAt(effectsByPosition, position);
  effects.pulses.push(pulse);

  if (pulse.kind === "damage") {
    effects.hitFlash = true;
  }
};

const mutableEffectsAt = (
  effectsByPosition: Map<string, MutableCellEffects>,
  position: Position,
): MutableCellEffects => {
  const key = keyForPosition(position);
  const existing = effectsByPosition.get(key);

  if (existing !== undefined) {
    return existing;
  }

  const created: MutableCellEffects = {
    pulses: [],
    hitFlash: false,
    motion: null,
  };
  effectsByPosition.set(key, created);

  return created;
};

const actorPositions = (state: GameState): ReadonlyMap<string, Position> => {
  const positions = new Map<string, Position>([["player", state.player.position]]);

  for (const entity of Object.values(state.entities)) {
    positions.set(entity.id, entity.position);
  }

  for (const event of state.log as readonly RuntimeLogEvent[]) {
    if (event.type !== "entity_died") {
      continue;
    }

    const data = asRecord(event.data);
    const entityId = stringValue(data?.entityId);
    const position = positionValue(data?.position);

    if (entityId !== null && position !== null && !positions.has(entityId)) {
      positions.set(entityId, position);
    }
  }

  return positions;
};

const asRecord = (value: unknown): RuntimeRecord | null =>
  value !== null && typeof value === "object"
    ? (value as RuntimeRecord)
    : null;

const numberValue = (value: unknown): number | null =>
  typeof value === "number" && Number.isFinite(value) ? value : null;

const stringValue = (value: unknown): string | null =>
  typeof value === "string" ? value : null;

const positionValue = (value: unknown): Position | null => {
  const record = asRecord(value);
  const x = numberValue(record?.x);
  const y = numberValue(record?.y);

  return x === null || y === null ? null : { x, y };
};

const keyForPosition = (position: Position): string =>
  `${position.x},${position.y}`;

const samePosition = (left: Position, right: Position): boolean =>
  left.x === right.x && left.y === right.y;

