const labelForLayer = (layer: GridLayer, fog: GridFogState): string => {
  if (fog === "unseen") {
    return "unseen";
  }

  if (fog === "remembered") {
    return "remembered terrain";
  }

  switch (layer) {
    case "player":
      return "you";
    case "enemy":
      return "enemy";
    case "npc":
      return "npc";
    case "item":
      return "item";
    case "trap":
      return "revealed trap";
    case "terrain":
      return "terrain";
    case "empty":
      return "empty";
  }
};

const layerAt = (
  state: GameState,
  position: Position,
  glyph: string,
  fog: GridFogState,
  entities: readonly EntityInstance[],
): GridLayer => {
  if (fog === "unseen" || glyph === " ") {
    return "empty";
  }

  if (fog === "remembered") {
    return "terrain";
  }

  if (samePosition(state.player.position, position)) {
    return "player";
  }

  if (entities.some((entity) => entity.kind === "enemy")) {
    return "enemy";
  }

  if (entities.some((entity) => entity.kind === "npc")) {
    return "npc";
  }

  if (entities.some((entity) => entity.kind === "item")) {
    return "item";
  }

  if (entities.some((entity) => entity.kind === "trap") && glyph === GLYPH_TRAP) {
    return "trap";
  }

  return "terrain";
};

